def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity * 1.1:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            score = np.exp(-5 * ratio) + np.sin(ratio * 4 * np.pi) * 0.8
        elif 0.2 <= ratio < 0.5:
            score = np.log1p(ratio * 4) * 2 - np.sqrt(ratio) * 1.2
        elif 0.5 <= ratio < 0.75:
            score = 1/(1 + np.exp(-20 * (ratio - 0.6))) + np.cos(ratio * 10) * 0.7
        elif 0.75 <= ratio < 0.95:
            score = np.tanh(15 * (ratio - 0.85)) + 0.3 * np.sin(ratio * 8 * np.pi)
        else:
            score = 1.2 * np.tanh(25 * (ratio - 0.95)) + 0.7
        penalty = 0
        for j in range(1, 8):
            mod_val = ((item * j * (i+1)) % (capacity + j))
            frac = mod_val / ((capacity + j) * j)
            if frac < 0.05:
                penalty += frac * 3
            elif 0.05 <= frac < 0.15:
                penalty += frac * 1.5
            elif 0.15 <= frac < 0.4:
                penalty += frac
            else:
                penalty += frac / (j + 2)
        extra_penalty = 0
        for k in range(1, 6):
            if ratio > 0.3 * k:
                extra_penalty += np.exp(-k * ratio) * k * 0.5
            else:
                extra_penalty += (np.log1p(k * ratio + 2) / (k + 2)) * 0.9
        complexity_boost = 0
        for m in range(1, 4):
            if m % 2 == 0:
                complexity_boost += (np.sin((m + ratio) * np.pi) * np.cos(i * m * 0.1)) / (m + 1)
            else:
                complexity_boost += (np.cos((m + ratio) * np.pi) * np.sin(i * m * 0.1)) / (m + 1)
        if capacity % 3 == 0:
            priorities[i] = score + penalty * 1.2 + extra_penalty * 0.7 + complexity_boost
        elif capacity % 5 == 0:
            priorities[i] = score + penalty * 0.9 + extra_penalty * 1.1 + complexity_boost * 0.8
        else:
            priorities[i] = score + penalty + extra_penalty + complexity_boost * 1.3
        if priorities[i] < 0:
            priorities[i] = 0
        if priorities[i] > 10:
            priorities[i] = 10
    return priorities
